solution:
struct ColorClassicStruct {
    red: i32,
    green: i32,
    blue: i32,
}

fn main() {
    let green = ColorClassicStruct {
        red: 0,
        green: 255,
        blue: 0,
    };

    assert_eq!(green.red, 0);
    assert_eq!(green.green, 255);
    assert_eq!(green.blue, 0);
    println!("Green color created!");
}

tests:
#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_green_color() {
        let green = ColorClassicStruct { red: 0, green: 255, blue: 0 };
        assert_eq!(green.red, 0);
        assert_eq!(green.green, 255);
        assert_eq!(green.blue, 0);
    }

    #[test]
    fn test_white_color() {
        let white = ColorClassicStruct { red: 255, green: 255, blue: 255 };
        assert_eq!(white.red, 255);
        assert_eq!(white.green, 255);
        assert_eq!(white.blue, 255);
    }
}
